func And(predicates ...predicate.Ebook) predicate.Ebook {
	return predicate.Ebook(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Ebook) predicate.Ebook {
	return predicate.Ebook(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Ebook) predicate.Ebook {
	return predicate.Ebook(sql.NotPredicates(p))
}
